#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

// min‑heap for integers
typedef struct {
    int *data;
    int size;
    int capacity;
} MinHeap;

MinHeap* createHeap(int cap) {
    MinHeap *h = (MinHeap*)malloc(sizeof(MinHeap));
    h->data = (int*)malloc(sizeof(int)*cap);
    h->size = 0;
    h->capacity = cap;
    return h;
}

void swap(int *a, int *b) { int t=*a; *a=*b; *b=t; }

void heapPush(MinHeap *h, int val) {
    int i = h->size++;
    h->data[i] = val;
    while (i && h->data[(i-1)/2] > h->data[i]) {
        swap(&h->data[i], &h->data[(i-1)/2]);
        i = (i-1)/2;
    }
}

int heapTop(MinHeap *h) { return h->data[0]; }

void heapPop(MinHeap *h) {
    h->data[0] = h->data[--h->size];
    int i = 0;
    while (1) {
        int l = 2*i+1, r = 2*i+2, smallest = i;
        if (l < h->size && h->data[l] < h->data[smallest]) smallest = l;
        if (r < h->size && h->data[r] < h->data[smallest]) smallest = r;
        if (smallest == i) break;
        swap(&h->data[i], &h->data[smallest]);
        i = smallest;
    }
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        char s[20]; long long K; scanf("%s %lld", s, &K);
        int len = strlen(s);
        MinHeap *h = createHeap(len);
        for (int i=0;i<len;i++) heapPush(h, s[i]-'0');
        while (K>0 && heapTop(h) < 9) {
            int d = heapTop(h);
            heapPop(h);
            heapPush(h, d+1);
            K--;
        }
        unsigned long long prod = 1ULL;
        for (int i=0;i<h->size;i++) prod *= (unsigned long long)h->data[i];
        printf("%llu\n", prod);
        free(h->data); free(h);
    }
    return 0;
}

