        string N; long long K; cin>>N>>K;
        priority_queue<int, vector<int>, greater<int>> pq;
        for(char c: N) pq.push(c-'0');
        while(K>0 && pq.top()<9){
            int d=pq.top(); pq.pop();
            pq.push(d+1);
            --K;
        }
        unsigned long long prod=1ULL;
        while(!pq.empty()){
            prod*= (unsigned long long)pq.top();
            pq.pop();
        }
        cout<<prod<<"\n";
    }
    return 0;
}

