const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  let K = Number(input[idx++]);
  const digits = N.split('').map(ch => Number(ch));
  // because length ≤ 7, simple linear scan each step is fine
  while (K > 0) {
    // find index of smallest digit < 9
    let minVal = 10, minIdx = -1;
    for (let i = 0; i < digits.length; i++) {
      if (digits[i] < minVal) {
        minVal = digits[i];
        minIdx = i;
      }
    }
    if (minVal === 9) break; // all are 9
    digits[minIdx] = minVal + 1;
    K--;
  }
  let prod = 1n;
  for (const d of digits) prod *= BigInt(d);
  results.push(prod.toString());
}
console.log(results.join('\n'));
